package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.BufferedReader;
import java.io.IOException;
import java.io.Reader;
import java.lang.reflect.Method;
import java.nio.charset.Charset;
import java.nio.file.Files;
import java.nio.file.Path;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class CSVParserParseTest {

    private Path mockPath;
    private Charset charset;
    private CSVFormat format;
    private BufferedReader mockReader;

    @BeforeEach
    void setUp() throws IOException {
        mockPath = mock(Path.class);
        charset = Charset.defaultCharset();
        format = mock(CSVFormat.class);
        mockReader = mock(BufferedReader.class);
    }

    @Test
    void parse_shouldReturnCSVParser_whenValidPathCharsetAndFormat() throws Exception {
        try (MockedStatic<Files> filesMockedStatic = Mockito.mockStatic(Files.class)) {
            filesMockedStatic.when(() -> Files.newBufferedReader(mockPath, charset)).thenReturn(mockReader);

            // Use reflection to call CSVParser.parse(Reader, CSVFormat) to avoid ambiguity
            Method parseReaderFormat = CSVParser.class.getMethod("parse", Reader.class, CSVFormat.class);

            CSVParser result;
            // Call the real method CSVParser.parse(Path, Charset, CSVFormat)
            try (MockedStatic<CSVParser> csvParserStatic = Mockito.mockStatic(CSVParser.class, Mockito.CALLS_REAL_METHODS)) {
                // When CSVParser.parse(Reader, CSVFormat) is called, call real method via reflection
                csvParserStatic.when(() -> CSVParser.parse(mockReader, format)).thenAnswer(invocation -> {
                    Reader r = invocation.getArgument(0);
                    CSVFormat f = invocation.getArgument(1);
                    return parseReaderFormat.invoke(null, r, f);
                });

                result = CSVParser.parse(mockPath, charset, format);
            }
            assertNotNull(result);
            assertTrue(result instanceof CSVParser);
        }
    }

    @Test
    void parse_shouldThrowNullPointerException_whenPathIsNull() throws Exception {
        // Use reflection to disambiguate call to parse(Path, Charset, CSVFormat)
        Method parsePathCharsetFormat = CSVParser.class.getMethod("parse", Path.class, Charset.class, CSVFormat.class);

        NullPointerException ex = assertThrows(NullPointerException.class,
                () -> {
                    try {
                        parsePathCharsetFormat.invoke(null, (Path) null, charset, format);
                    } catch (Exception e) {
                        // unwrap InvocationTargetException
                        Throwable cause = e.getCause();
                        if (cause instanceof NullPointerException) {
                            throw (NullPointerException) cause;
                        }
                        throw e;
                    }
                });
        assertEquals("path", ex.getMessage());
    }

    @Test
    void parse_shouldThrowNullPointerException_whenFormatIsNull() throws Exception {
        // Use reflection to disambiguate call to parse(Path, Charset, CSVFormat)
        Method parsePathCharsetFormat = CSVParser.class.getMethod("parse", Path.class, Charset.class, CSVFormat.class);

        NullPointerException ex = assertThrows(NullPointerException.class,
                () -> {
                    try {
                        parsePathCharsetFormat.invoke(null, mockPath, charset, null);
                    } catch (Exception e) {
                        Throwable cause = e.getCause();
                        if (cause instanceof NullPointerException) {
                            throw (NullPointerException) cause;
                        }
                        throw e;
                    }
                });
        assertEquals("format", ex.getMessage());
    }

    @Test
    void parse_shouldThrowIOException_whenFilesNewBufferedReaderThrows() throws Exception {
        try (MockedStatic<Files> filesMockedStatic = Mockito.mockStatic(Files.class)) {
            filesMockedStatic.when(() -> Files.newBufferedReader(mockPath, charset)).thenThrow(new IOException("io error"));

            // Use reflection to disambiguate call to parse(Path, Charset, CSVFormat)
            Method parsePathCharsetFormat = CSVParser.class.getMethod("parse", Path.class, Charset.class, CSVFormat.class);

            IOException ex = assertThrows(IOException.class, () -> {
                try {
                    parsePathCharsetFormat.invoke(null, mockPath, charset, format);
                } catch (Exception e) {
                    Throwable cause = e.getCause();
                    if (cause instanceof IOException) {
                        throw (IOException) cause;
                    }
                    throw e;
                }
            });
            assertEquals("io error", ex.getMessage());
        }
    }

}
